import json

def solve(grid):
    output_grid = [row[:] for row in grid]
    rows = len(grid)
    cols = len(grid[0])

    for r in range(rows):
        row = output_grid[r]
        # Find all indices of non-zero numbers
        non_zero_indices = {val: [c for c, v in enumerate(row) if v == val] for val in set(row) if val != 0}

        for val, indices in non_zero_indices.items():
            if len(indices) < 2:
                continue

            for i in range(len(indices)):
                for j in range(i + 1, len(indices)):
                    c1 = indices[i]
                    c2 = indices[j]

                    if c2 == c1 + 1:
                        continue

                    # Check the segment between c1 and c2
                    segment = row[c1+1:c2]
                    if not segment:
                        continue

                    # Check if all elements in the segment are non-zero and different from val
                    is_valid_segment = True
                    fill_val = -1

                    if segment[0] == 0 or segment[0] == val:
                        is_valid_segment = False
                    else:
                        fill_val = segment[0]

                    if is_valid_segment:
                        for k in range(1, len(segment)):
                            if segment[k] != fill_val:
                                is_valid_segment = False
                                break

                    if is_valid_segment:
                        for c in range(c1 + 1, c2):
                            output_grid[r][c] = val

    return output_grid

def format_grid(grid):
    return "\n".join(" ".join(map(str, row)) for row in grid)

input_grid_str = """0 4 4 4 0 0 0 0 0 0
3 3 3 3 3 0 0 0 0 0
3 3 3 3 3 0 0 0 0 0
3 3 3 3 3 0 0 0 0 0
3 3 3 3 3 0 0 0 0 0
0 4 4 4 0 0 4 4 4 0
0 0 0 0 0 3 4 4 4 3
0 0 0 0 0 3 4 4 4 3
0 0 0 0 0 3 4 4 4 3
0 0 0 0 0 3 4 4 4 3"""

input_grid = [list(map(int, line.split())) for line in input_grid_str.split('\n')]
output_grid = solve(input_grid)
output_grid_str = format_grid(output_grid)

rule = "In each row, if a segment of cells of the same non-zero color is horizontally enclosed by cells of another single non-zero color, the segment's color changes to the enclosing color."
result = {"rule": rule, "grid": output_grid_str}
print(json.dumps(result, indent=None, separators=(',', ':')))
